.//horizontal slider: 0, vertical slider: 1
uniform int orient;
//the widget's current normalized value
uniform float nrmValue;
uniform float defaultValue;
uniform vec2 minMax;
uniform vec4 bgColor;
uniform vec4 indColor;
uniform vec4 knobColor;
uniform int knobSize;
//uniform float pOffset;
//uniform float scale;

layout(location = 0) out vec4 fragColor;

float map(float s, float a1, float a2, float b1, float b2)
{
    return b1 + (s-a1)*(b2-b1)/(a2-a1);
}

vec4 over(vec4 tOver, vec4 tUnder)
{
    return ((1.0-tOver.a)*tUnder) + tOver.a * tOver;
}

void main() {

    //level use v if orient is 1 else use u
    float level = orient == 1.0 ? vUV.t : vUV.s;
	//Flips the incoming text and textures to the correct orientation
	vec2 fUV = orient == 1.0 ? (vec2(0.0, 1.0)
								+ (vUV.ts*vec2(1.0, -1.0))) : vUV.st;
	float coord = orient == 1.0 ? gl_FragCoord.y : gl_FragCoord.x;
    float sliderPixLength = uTD2DInfos[0].res.z;
	vec4 color = vec4(0.0);
	//ranged value
	float rmin = minMax.x;
	float rmax = minMax.y;
	//normalize knob size
	float nmKnobSize = knobSize / sliderPixLength;
	float nmKnobSizeH = nmKnobSize/2.0;
	float nmDefault = (defaultValue-rmin) / (rmax - rmin);
	float nmValueKnob = nrmValue * (1-nmKnobSize) + nmKnobSizeH;
    float pOffset = -nrmValue * ((sliderPixLength-knobSize) / knobSize);
    float scale = sliderPixLength / knobSize;
    //knob uv
    vec2 knobUV =  vec2(fUV.s*scale+pOffset, fUV.t);

    //load textures
    //vec4 textLayer = texture(sTD2DInputs[0], fUV);
	vec4 bgLayer = texture(sTD2DInputs[1], fUV);
	vec4 knobLayer = texture(sTD2DInputs[0], knobUV);

	//Level indicator color
    if (level < nmValueKnob-(nmKnobSizeH) && level > nmDefault ||
					level < nmDefault && level >
                    nmValueKnob+(nmKnobSizeH))
	//slider range color
    {
        color = over(indColor, color);
  	}
    else
	//slider bg color
  	{
  	   color = bgColor;
  	}
	//remap slider range in consideration of knob width
	float remapValue = map(nrmValue, 0, 1, nmKnobSizeH,
                                                1-(nmKnobSizeH));
    //float remapValue = map(normValue, 0, 1, 0, 1);
    //knob color
	if (level > (remapValue - (nmKnobSizeH)) &&
								      level < (remapValue + (nmKnobSizeH)))
    //knob color and texture
    {
    color = over(knobColor, color);
    color = over(knobLayer, color);
    }
	//Texture mix
    color = over(color, bgLayer);
    //color = over(textLayer, color);
    //color = vec4(orient);
    //color = vec4(float(level < (remapValue + (nmKnobSizeH))));
    //color = vec4(uTD2DInfos[0].res.z);
	fragColor = color;
}

